sql:
SELECT election_id, MIN(num_votes) AS min_votes_received
FROM votes
GROUP BY election_id;

SELECT candidate_name
FROM candidates
WHERE candidate_id IN (SELECT candidate_id FROM candidate_groups WHERE group_id = 0);

external_knowledge:
- In the context of this query, "top-performing candidates" refers to those with the highest number of votes within their party;
- "Highest-performing voting booths" are those with the most votes cast;
- A "party" in this context is a political organization that the candidates belong to;
- An "electoral district" is a geographic area that the voting booths belong to.

sql:
SELECT election_name, election_type, total_votes_cast, turnout_percentage
FROM elections
WHERE turnout_percentage >= 50.0;

SELECT AVG(percentage) AS avg_percentage
FROM electoral_district_results
WHERE election_id = 1;

SELECT SUM(num_votes) AS total_votes_cast
FROM votes
WHERE election_id = 1;
